mapper.select:
SELECT content,is_mch_send,nike_name,img,add_date,send_id,receive_id FROM ( SELECT o.content, o.is_mch_send, o.send_id, o.receive_id, IF ( o.is_mch_send = 0, u.user_name, m.NAME ) AS nike_name, IF ( o.is_mch_send = 0, u.headimgurl, m.head_img ) AS img, o.add_date FROM `lkt_online_message` o LEFT JOIN lkt_user u ON o.send_id = u.user_id OR o.receive_id = u.user_id LEFT JOIN lkt_mch m ON o.send_id = m.id OR m.id = o.receive_id WHERE o.send_id = #{userId} AND o.receive_id = #{mchId} AND o.is_mch_send = 0 AND o.store_id = #{storeId}
#{id}
UNION SELECT o.content, o.is_mch_send, o.send_id, o.receive_id, IF ( o.is_mch_send = 0, u.user_name, m.NAME ) AS nike_name, IF ( o.is_mch_send = 0, u.headimgurl, m.head_img ) AS img, o.add_date FROM `lkt_online_message` o LEFT JOIN lkt_user u ON o.send_id = u.user_id OR o.receive_id = u.user_id LEFT JOIN lkt_mch m ON o.send_id = m.id OR m.id = o.receive_id WHERE o.send_id = #{mchId} AND o.receive_id = #{userId} AND o.is_mch_send = 1 AND o.store_id = #{storeId}
#{id}
) as msg order by add_date asc

SELECT u.user_name, u.user_id, u.mch_id, u.send_id, u.store_id, u.is_mch_send, u.headimgurl, u. no_read_num FROM ( SELECT u.user_name, u.user_id, o.receive_id AS mch_id, o.send_id, o.store_id, o.is_mch_send, u.headimgurl, count( o.is_read = 0 OR NULL) over(partition by o.send_id) AS no_read_num, ROW_NUMBER() over(partition by o.send_id) AS top, 0 AS is_online FROM `lkt_online_message` o LEFT JOIN lkt_user u ON o.send_id = u.user_id ) AS u WHERE u.top < 2 AND u.mch_id = #{mchId} and u.is_mch_send = 0 and u.store_id = #{storeId} and u.user_id is not null
and u.send_id = #{userId}
and u.user_name like concat('%',#{userName},'%')

SELECT a.name, a.mch_id, a.user_id, a.headimgurl, a.receive_id, a.no_read_num, a.is_online FROM ( SELECT m.name, receive_id AS mch_id, o.send_id AS user_id, m.head_img AS headimgurl, o.receive_id, count( o.is_mch_send = 1 AND o.is_read = 0 OR NULL ) over(partition by o.receive_id) AS no_read_num, 0 AS is_online, ROW_NUMBER() over(partition by o.receive_id) AS top FROM `lkt_online_message` o LEFT JOIN lkt_mch m ON o.receive_id = m.id WHERE o.send_id = #{userId} AND o.store_id = #{storeId}
and o.receive_id = #{mchId}
and m.name like concat('%',#{mchName},'%')
) as a WHERE a.top < 2
